const results = [];
for (const item of $input.all()) {
  const json = item.json;
  const jobPosterName = json.jobPosterName ?? json.jobPoster?.name ?? json.job_poster_name ?? null;
  const jobPosterUrl = json.jobPosterProfileUrl ?? json.jobPoster?.profileUrl ?? json.jobPoster?.profile ?? json.job_poster_profile_url ?? null;
  const timePosted = json.postedAt || json.publishedAt || null;
  results.push({
    json: {
      id: json.id ?? '',
      job_title: json.title ?? json.job_title ?? '',
      job_description: (json.descriptionText ?? json.description ?? '') || null,
      job_url: (json.link ?? json.url ?? '') || null,
      company_name: (json.companyName ?? json.company ?? '') || null,
      company_url: (json.companyLinkedinUrl ?? json.companyUrl ?? '') || null,
      seniority_level: (json.seniorityLevel ?? json.seniority ?? '') || null,
      employment_type: (json.employmentType ?? json.employment ?? '') || null,
      time_posted: timePosted,
      apply_url: (json.applyUrl ?? json.applyLink ?? '') || null,
      job_poster_name: jobPosterName,
      job_poster_profile_url: jobPosterUrl
    }
  });
}
return results;
